ALTER TABLE "DIRKSPZM32"."ISI_ARTIKEL" ADD CONSTRAINT "CHECK_ISI_ARTIKEL_MENGE_BASIS" CHECK (MENGE_BASIS in ('LKE','LHM', 'LTE')) ENABLE;
ALTER TABLE "DIRKSPZM32"."ISI_ARTIKEL" ADD CONSTRAINT "CHECK_LABOR_VORGABE_STATUS" CHECK (LABOR_VORGABE_STATUS in ('Q','U','B','G','F')) ENABLE;
ALTER TABLE "DIRKSPZM32"."ISI_ARTIKEL" ADD CONSTRAINT "CHECK_LAUFRICHTUNG" CHECK (LAUFRICHTUNG in ('','M','O','E')) ENABLE;
ALTER TABLE "DIRKSPZM32"."ISI_ARTIKEL" ADD CONSTRAINT "CHK_ISI_ARTIKEL_ABC" CHECK (abc in (1, 2, 3)) ENABLE;
ALTER TABLE "DIRKSPZM32"."ISI_ARTIKEL" ADD CONSTRAINT "CHK_ISI_ARTIKEL_AKTIV" CHECK (aktiv in ('T','F')) ENABLE;
ALTER TABLE "DIRKSPZM32"."ISI_ARTIKEL" ADD CONSTRAINT "CHK_ISI_ARTIKEL_LEG_ZUSCHL" CHECK (leg_zuschlag_p_1000kg is null OR (leg_zuschlag_p_1000kg is not null AND einsatzgewicht_kg is not null AND leg_zuschlag_artikel_id is not null)) ENABLE;
ALTER TABLE "DIRKSPZM32"."ISI_ARTIKEL" ADD CONSTRAINT "PK_ARTIKEL" PRIMARY KEY ("ARTIKEL_ID")
  USING INDEX  ENABLE;
ALTER TABLE "DIRKSPZM32"."ISI_ARTIKEL" ADD CONSTRAINT "UK_ARTIKEL" UNIQUE ("ARTIKEL")
  USING INDEX  ENABLE;
ALTER TABLE "DIRKSPZM32"."ISI_ARTIKEL" ADD CONSTRAINT "UK_ARTIKEL_KURZ" UNIQUE ("ARTIKEL_KURZ")
  USING INDEX  ENABLE;


